import type * as DMMF from '@prisma/dmmf'

/**
 * Maps a Prisma scalar type name to its TypeScript equivalent.
 * DateTime and Bytes are represented as strings since they travel over HTTP as
 * ISO-8601 and base64 respectively.  Decimal uses string to preserve precision.
 */
export function scalarToTs(prismaType: string): string {
  switch (prismaType) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'Decimal':
      return 'string'
    case 'DateTime':
      return 'string'
    case 'Json':
      return 'unknown'
    case 'Bytes':
      return 'string'
    default:
      return 'unknown'
  }
}

/** Returns the TypeScript type string for a scalar or enum DMMF field. */
export function fieldToTsType(field: DMMF.Field): string {
  if (field.kind === 'enum') {
    return field.type
  }
  return scalarToTs(field.type)
}

/** Returns true when a field carries data directly (not a relation). */
export function isScalarOrEnumField(field: DMMF.Field): boolean {
  return field.kind === 'scalar' || field.kind === 'enum'
}

/** Returns true when a field can uniquely identify a record. */
export function isUniqueField(field: DMMF.Field): boolean {
  return field.isId || field.isUnique
}

