  const base = fieldToTsType(field)
  const withList = field.isList ? `${base}[]` : base
  return !field.isRequired && !field.isList ? `${withList} | null` : withList
}

/** Generates the TypeScript interface representing a model's scalar/enum fields. */
export function generateModelInterface(model: DMMF.Model): string {
  const lines = model.fields
    .filter(isScalarOrEnumField)
    .map((f) => fieldLine(f.name, scalarFieldTsType(f), false))

  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

/**
 * Generates the input type used to locate a single record.
 * All fields are optional so callers can use any combination of unique fields.
 * Returns an empty string when the model has no uniquely-identifying fields.
 */
export function generateWhereUniqueInput(model: DMMF.Model): string {
  const fields = model.fields.filter((f) => isScalarOrEnumField(f) && isUniqueField(f))
  if (fields.length === 0) return ''

  const lines = fields.map((f) => fieldLine(f.name, fieldToTsType(f), true))
  return `export interface ${model.name}WhereUniqueInput {\n${lines.join('\n')}\n}`
}

/**
 * Generates the input type for record creation.
 * ID fields and read-only fields are excluded; fields with defaults are optional.
 */
export function generateCreateInput(model: DMMF.Model): string {
  const lines = model.fields
    .filter((f) => isScalarOrEnumField(f) && !f.isReadOnly && !f.isId)
    .map((f) => {
      const isOptional = !f.isRequired || f.hasDefaultValue
      return fieldLine(f.name, scalarFieldTsType(f), isOptional)
    })

  return `export interface ${model.name}CreateInput {\n${lines.join('\n')}\n}`
}

/** Generates the input type for record updates — every field is optional. */
export function generateUpdateInput(model: DMMF.Model): string {
  const lines = model.fields
    .filter((f) => isScalarOrEnumField(f) && !f.isReadOnly && !f.isId)
    .map((f) => fieldLine(f.name, scalarFieldTsType(f), true))

  return `export interface ${model.name}UpdateInput {\n${lines.join('\n')}\n}`
}

/** Returns the lowercase REST resource path segment for a model name. */
export function resourcePath(modelName: string): string {
  return uncapitalize(modelName)
}

/** Generates the REST client class that wraps all CRUD operations for a model. */
export function generateRestClientClass(model: DMMF.Model): string {
  const { name } = model
  const resource = resourcePath(name)
  const hasUniqueFields = model.fields.some((f) => isScalarOrEnumField(f) && isUniqueField(f))
  const whereType = hasUniqueFields ? `${name}WhereUniqueInput` : 'Record<string, string | number>'

  return `export class ${name}RestClient {
