  generateRestClientClass,
  generateUpdateInput,
  generateWhereUniqueInput,
  resourcePath,
} from '../model-codegen'

function makeField(overrides: Partial<DMMF.Field>): DMMF.Field {
  return {
    kind: 'scalar',
    name: 'field',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    type: 'String',
    ...overrides,
  } as DMMF.Field
}

function makeModel(name: string, fields: DMMF.Field[]): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  } as DMMF.Model
}

const userModel = makeModel('User', [
  makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
  makeField({ name: 'email', type: 'String', isUnique: true }),
  makeField({ name: 'name', type: 'String', isRequired: false }),
  makeField({ name: 'age', type: 'Int', isRequired: false }),
  makeField({ name: 'posts', kind: 'object', type: 'Post', isList: true }),
])

